parameters.jsCode:
// Pull text from Anthropic response
const body = $input.first().json;
const lastText = (body.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n');
// Extract JSON block
const match = lastText.match(/\{[\s\S]*\}/);
if (!match) throw new Error('No JSON in research response');
const research = JSON.parse(match[0]);
return [{ json: { research } }];

// Build batch inserts. Each table gets its own POST.
const run = $('Webhook: kick off').item.json;
const r = $json.research;
const clientId = run.client_id;
const runId    = run.run_id;
const rows = {
  competitors:    (r.competitors    || []).map(c => ({ ...c, client_id: clientId, run_id: runId })),
  customer_voice: (r.customer_voice || []).map(v => ({ ...v, client_id: clientId, run_id: runId })),
  obstacles:      (r.obstacles      || []).map(o => ({ ...o, client_id: clientId, run_id: runId })),
  headline_bank:  (r.headlines      || []).map(h => ({ ...h, client_id: clientId, run_id: runId })),
  icps:           (r.icp || r.icps  || []).map(i => ({ ...i, client_id: clientId, is_ai_draft: true, ai_drafted_at: new Date().toISOString() })),
  brand_profile:  r.brand_profile ? [{ ...r.brand_profile, client_id: clientId, is_ai_draft: true, ai_drafted_at: new Date().toISOString() }] : []
};
return [{ json: { rows, research: r } }];

